queries.sql:
SELECT novelist, COUNT(*) AS Movie_Count
FROM Movies
GROUP BY novelist;

SELECT playwright, COUNT(*) AS Movie_Count
FROM Movies
GROUP BY playwright;

SELECT novelist, playwright, COUNT(*) AS Movie_Count
FROM Movies
GROUP BY novelist, playwright;

SELECT novelist, playwright, title, release_year
FROM Movies
ORDER BY novelist, playwright, release_year;

SELECT playwright, title, release_year
FROM Movies
ORDER BY playwright, release_year;

SELECT novelist, title, release_year
FROM Movies
ORDER BY novelist, release_year;

