PREFIX : <http://ambrosia.example.org/streamingservice#>
PREFIX p: <http://ambrosia.example.org/streamingservice/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?playwright_g (COUNT(*) AS ?agg) WHERE {
  ?movies a :Movies .
  ?movies p:playwright ?playwright_g .
}
GROUP BY ?playwright_g }
  component_2: { SELECT ?novelist_g (COUNT(*) AS ?agg) WHERE {
  ?movies a :Movies .
  ?movies p:novelist ?novelist_g .
}
GROUP BY ?novelist_g }
  full: { SELECT ?novelist_g ?playwright_g (COUNT(*) AS ?agg) WHERE {
  ?movies a :Movies .
  ?movies p:novelist ?novelist_g .
  ?movies p:playwright ?playwright_g .
}
GROUP BY ?novelist_g ?playwright_g }
}

